18	namespace {
19	struct TargetCodegenPipelineOptions
20	    : public PassPipelineOptions<TargetCodegenPipelineOptions> {
21	  PassOptions::Option<bool> allowBreaksInLoops{
22	      *this, "loops-may-have-break",
23	      llvm::cl::desc("Enable break statements in loops."),
24	      llvm::cl::init(true)};
25	  PassOptions::Option<std::string> target{
26	      *this, "convert-to", llvm::cl::desc("Conversion target specifier."),
27	      llvm::cl::init("")};
28	};
