31	static void addQIRConversionPipeline(PassManager &pm, StringRef convertTo) {
32	  auto convertFields = convertTo.split(':');
33	  if (convertFields.first == "qir" || convertFields.first == "qir-full") {
34	    cudaq::opt::addConvertToQIRAPIPipeline(pm, "full:" +
35	                                                   convertFields.second.str());
36	  } else if (convertFields.first == "qir-base") {
37	    pm.addNestedPass<func::FuncOp>(cudaq::opt::createDelayMeasurements());
38	    cudaq::opt::addConvertToQIRAPIPipeline(pm, "base-profile:" +
39	                                                   convertFields.second.str());
40	  } else if (convertFields.first == "qir-adaptive") {
41	    cudaq::opt::addConvertToQIRAPIPipeline(pm, "adaptive-profile:" +
42	                                                   convertFields.second.str());
43	  } else {
44	    emitError(UnknownLoc::get(pm.getContext()),
45	              "convert to QIR must be given a valid specification to use.");
46	  }
47	}
48	
49	template <bool isJIT>
50	void createCommonTargetCodegenPipeline(
51	    PassManager &pm, const TargetCodegenPipelineOptions &options) {
52	  if constexpr (isJIT) {
53	    pm.addNestedPass<func::FuncOp>(cudaq::opt::createExpandMeasurementsPass());
54	    pm.addNestedPass<func::FuncOp>(cudaq::opt::createClassicalMemToReg());
55	    pm.addNestedPass<func::FuncOp>(createCSEPass());
56	    // One last gasp of loop unrolling pass, primarily to catch the expanded
57	    // measurements.
58	    pm.addNestedPass<func::FuncOp>(cudaq::opt::createLoopNormalize());
59	    cudaq::opt::LoopUnrollOptions luo;
60	    luo.allowBreak = options.allowBreaksInLoops;
61	    pm.addNestedPass<func::FuncOp>(cudaq::opt::createLoopUnroll(luo));
62	    pm.addNestedPass<func::FuncOp>(createCanonicalizerPass());
63	  } else {
64	    pm.addNestedPass<func::FuncOp>(cudaq::opt::createApplyControlNegations());
65	    cudaq::opt::addAggressiveInlining(pm);
66	    pm.addNestedPass<func::FuncOp>(createCanonicalizerPass());
67	    pm.addNestedPass<func::FuncOp>(cudaq::opt::createUnwindLowering());
68	    pm.addNestedPass<func::FuncOp>(createCanonicalizerPass());
69	    pm.addNestedPass<func::FuncOp>(cudaq::opt::createExpandMeasurementsPass());
70	    pm.addNestedPass<func::FuncOp>(cudaq::opt::createClassicalMemToReg());
71	    pm.addNestedPass<func::FuncOp>(createCanonicalizerPass());
72	    pm.addNestedPass<func::FuncOp>(createCSEPass());
73	    pm.addNestedPass<func::FuncOp>(cudaq::opt::createQuakeAddDeallocs());
74	    pm.addNestedPass<func::FuncOp>(cudaq::opt::createQuakeAddMetadata());
75	    pm.addPass(cudaq::opt::createQuakePropagateMetadata());
76	    pm.addNestedPass<func::FuncOp>(cudaq::opt::createLoopNormalize());
77	    cudaq::opt::LoopUnrollOptions luo;
78	    luo.allowBreak = options.allowBreaksInLoops;
79	    pm.addNestedPass<func::FuncOp>(cudaq::opt::createLoopUnroll(luo));
80	    pm.addNestedPass<func::FuncOp>(createCanonicalizerPass());
81	    pm.addNestedPass<func::FuncOp>(createCSEPass());
82	    // A final round of apply specialization after loop unrolling. This should
83	    // eliminate any residual control structures so the kernel specializations
84	    // can succeed.
85	    pm.addPass(cudaq::opt::createApplySpecialization());
86	    // If there was any specialization, we want another round in inlining to
87	    // inline the apply calls properly.
88	    cudaq::opt::addAggressiveInlining(pm);
89	  }
90	  cudaq::opt::addLowerToCFG(pm);
91	  pm.addNestedPass<func::FuncOp>(cudaq::opt::createStackFramePrealloc());
92	  pm.addNestedPass<func::FuncOp>(cudaq::opt::createCombineQuantumAllocations());
93	  pm.addNestedPass<func::FuncOp>(createCanonicalizerPass());
94	  pm.addNestedPass<func::FuncOp>(createCSEPass());
95	}
96	
97	template <bool isJIT, bool useValueSemantics = false>
98	void createTargetCodegenPipeline(PassManager &pm,
99	                                 const TargetCodegenPipelineOptions &options) {
100	  createCommonTargetCodegenPipeline<isJIT>(pm, options);
101	  if (useValueSemantics) {
102	    pm.addNestedPass<func::FuncOp>(
103	        cudaq::opt::createFactorQuantumAllocations());
104	    pm.addNestedPass<func::FuncOp>(cudaq::opt::createDeadQuantumElimination());
105	    pm.addNestedPass<func::FuncOp>(cudaq::opt::createCableRoughIn());
106	    pm.addNestedPass<func::FuncOp>(createCanonicalizerPass());
107	    pm.addNestedPass<func::FuncOp>(cudaq::opt::createMemToReg());
108	    pm.addNestedPass<func::FuncOp>(createCanonicalizerPass());
109	  }
110	  ::addQIRConversionPipeline(pm, options.target);
111	  // QIR conversion may introduce cc.loop, lower to cf.
112	  cudaq::opt::addLowerToCFG(pm);
113	  cudaq::opt::ReturnToOutputLogOptions opts;
114	  // Only allow dynamic results with full QIR (local simulator targets).
115	  auto tgt = StringRef(options.target).split(':').first;
116	  opts.allowDynamicResult = tgt == "qir" || tgt == "qir-full";
117	  pm.addPass(cudaq::opt::createReturnToOutputLog(opts));
118	  pm.addPass(createConvertMathToFuncs());
119	  pm.addPass(createSymbolDCEPass());
120	  pm.addPass(cudaq::opt::createCCToLLVM());
121	}
122	
123	template <bool isJIT>
124	void createTargetCodegenPipeline(PassManager &pm, StringRef convertTo) {
125	  auto convertFields = convertTo.split(':');
126	  TargetCodegenPipelineOptions opts;
127	  opts.allowBreaksInLoops = convertFields.first == "qir-adaptive";
128	  opts.target = convertTo.str();
129	  createTargetCodegenPipeline<isJIT>(pm, opts);
130	}
