137	void cudaq::opt::addAOTPipelineConvertToQIR(PassManager &pm,
138	                                            StringRef convertTo) {
139	  if (convertTo.empty())
140	    convertTo = "qir";
141	  ::createTargetCodegenPipeline</*JIT=*/false>(pm, convertTo);
142	}
