144	void cudaq::opt::createPipelineTransformsForPythonToOpenQASM(
145	    OpPassManager &pm) {
146	  pm.addPass(createLambdaLifting());
147	  // Run most of the passes from hardware pipelines.
148	  pm.addNestedPass<func::FuncOp>(createCanonicalizerPass());
149	  pm.addNestedPass<func::FuncOp>(createCSEPass());
150	  pm.addNestedPass<func::FuncOp>(createClassicalMemToReg());
151	  pm.addNestedPass<func::FuncOp>(createLoopNormalize());
152	  pm.addNestedPass<func::FuncOp>(createLoopUnroll());
153	  pm.addNestedPass<func::FuncOp>(createCanonicalizerPass());
154	  pm.addNestedPass<func::FuncOp>(createLiftArrayAlloc());
155	  pm.addPass(createGlobalizeArrayValues());
156	  pm.addNestedPass<func::FuncOp>(createCanonicalizerPass());
157	  pm.addPass(createGetConcreteMatrix());
158	  pm.addPass(createUnitarySynthesis());
159	  pm.addPass(createApplySpecialization());
160	  addAggressiveInlining(pm);
161	  pm.addPass(createSymbolDCEPass());
162	  pm.addNestedPass<func::FuncOp>(createCanonicalizerPass());
163	  pm.addNestedPass<func::FuncOp>(createCSEPass());
164	  pm.addNestedPass<func::FuncOp>(createMultiControlDecomposition());
165	  pm.addPass(createDecomposition(
166	      {.basis = {"h", "s", "t", "rx", "ry", "rz", "x", "y", "z", "x(1)"},
167	       .disabledPatterns = {},
168	       .enabledPatterns = {}}));
169	  pm.addPass(createQuakeToCCPrep());
170	  pm.addNestedPass<func::FuncOp>(createCanonicalizerPass());
171	  pm.addNestedPass<func::FuncOp>(createExpandControlVeqs());
172	  pm.addNestedPass<func::FuncOp>(createCombineQuantumAllocations());
173	  pm.addPass(createSymbolDCEPass());
174	}
