176	void cudaq::opt::addPipelineTranslateToOpenQASM(PassManager &pm) {
177	  pm.addNestedPass<func::FuncOp>(createClassicalMemToReg());
178	  pm.addNestedPass<func::FuncOp>(createCanonicalizerPass());
179	  pm.addNestedPass<func::FuncOp>(createDeadStoreRemoval());
180	  pm.addPass(createSymbolDCEPass());
181	}
