183	void cudaq::opt::addPipelineTranslateToIQMJson(PassManager &pm) {
184	  pm.addNestedPass<func::FuncOp>(createExpandMeasurementsPass());
185	  pm.addNestedPass<func::FuncOp>(createCSEPass());
186	  pm.addNestedPass<func::FuncOp>(createLoopNormalize());
187	  LoopUnrollOptions luo;
188	  pm.addNestedPass<func::FuncOp>(createLoopUnroll(luo));
189	  pm.addNestedPass<func::FuncOp>(createCanonicalizerPass());
190	  addLowerToCFG(pm);
191	  pm.addNestedPass<func::FuncOp>(createStackFramePrealloc());
192	  pm.addNestedPass<func::FuncOp>(createCombineQuantumAllocations());
193	  pm.addNestedPass<func::FuncOp>(createCanonicalizerPass());
194	  pm.addPass(createSymbolDCEPass());
195	}
