105	static cl::opt<std::string>
106	    resourceDir("resource-dir",
107	                cl::desc("Specify the clang resource directory"), cl::init(""));
108	
109	static cl::list<std::string>
110	    macroDefines("D", cl::desc("Define preprocessor macro."));
111	
112	static cl::list<std::string> includePath("I", cl::desc("Include file path."));
113	
114	static cl::list<std::string>
115	    systemIncludePath("J", cl::desc("System include file path."));
116	
117	static cl::list<std::string>
118	    extraClangArgs("Xcudaq", cl::desc("Extra options to pass to clang++"));
119	
120	static cl::opt<std::string> stdCpp(
121	    "std",
122	    cl::desc("Specify the C++ standard (c++20, c++23). The default is c++20."),
123	    cl::init("c++20"));
124	
125	inline bool isStdinInput(StringRef str) { return str == "-"; }
126	
127	//===----------------------------------------------------------------------===//
128	// Helper classes.
129	//===----------------------------------------------------------------------===//
130	
131	namespace {
132	/// Consumer that runs a pair of AST consumers at the same time.
133	class CudaQASTConsumer : public clang::ASTConsumer {
134	public:
135	  CudaQASTConsumer(std::unique_ptr<clang::ASTConsumer> &consumer0,
136	                   std::unique_ptr<clang::ASTConsumer> &consumer1) {
137	    assert(consumer0 && consumer1 && "AST Consumers must be instantiated");
138	    consumers.emplace_back(consumer1.release());
139	    consumers.emplace_back(consumer0.release());
140	  }
141	
142	  virtual ~CudaQASTConsumer() {
143	    for (auto *p : consumers)
144	      delete p;
145	    consumers.clear();
146	  }
147	
148	  // The following is boilerplate to override all the virtual functions that
149	  // appear in the union of the two AST consumers, namely clang::BackendConsumer
150	  // and nvqpp::MLIRASTConsumer.
151	  template <typename A, typename B>
152	  inline void applyConsumers(void (clang::ASTConsumer::*fun)(A), B &&arg) {
153	    for (auto *c : consumers)
154	      (c->*fun)(arg);
155	  }
156	  void HandleTranslationUnit(clang::ASTContext &ctxt) override {
157	    applyConsumers(&clang::ASTConsumer::HandleTranslationUnit, ctxt);
158	  }
159	  void HandleCXXStaticMemberVarInstantiation(clang::VarDecl *VD) override {
160	    applyConsumers(&clang::ASTConsumer::HandleCXXStaticMemberVarInstantiation,
161	                   std::move(VD));
162	  }
163	  void Initialize(clang::ASTContext &Ctx) override {
164	    applyConsumers(&clang::ASTConsumer::Initialize, Ctx);
165	  }
166	  bool HandleTopLevelDecl(clang::DeclGroupRef D) override {
167	    bool result = true;
168	    for (auto *c : consumers)
169	      result = result && c->HandleTopLevelDecl(D);
170	    return result;
171	  }
172	  void HandleInlineFunctionDefinition(clang::FunctionDecl *D) override {
173	    applyConsumers(&clang::ASTConsumer::HandleInlineFunctionDefinition,
174	                   std::move(D));
175	  }
176	  void HandleInterestingDecl(clang::DeclGroupRef D) override {
177	    applyConsumers(&clang::ASTConsumer::HandleInterestingDecl, std::move(D));
178	  }
179	  void HandleTagDeclDefinition(clang::TagDecl *D) override {
180	    applyConsumers(&clang::ASTConsumer::HandleTagDeclDefinition, std::move(D));
181	  }
182	  void HandleTagDeclRequiredDefinition(const clang::TagDecl *D) override {
183	    applyConsumers(&clang::ASTConsumer::HandleTagDeclRequiredDefinition,
184	                   std::move(D));
185	  }
186	  void CompleteTentativeDefinition(clang::VarDecl *D) override {
187	    applyConsumers(&clang::ASTConsumer::CompleteTentativeDefinition,
188	                   std::move(D));
189	  }
190	  void AssignInheritanceModel(clang::CXXRecordDecl *RD) override {
191	    applyConsumers(&clang::ASTConsumer::AssignInheritanceModel, std::move(RD));
192	  }
193	  void HandleVTable(clang::CXXRecordDecl *RD) override {
194	    applyConsumers(&clang::ASTConsumer::HandleVTable, std::move(RD));
195	  }
196	
197	private:
198	  SmallVector<clang::ASTConsumer *, 2> consumers;
199	};
200	
201	/// Action to create both the LLVM IR for the entire C++ compilation unit and to
202	/// translate the CUDA-Q kernels.
203	class CudaQAction : public clang::EmitLLVMAction {
204	public:
205	  using Base = clang::EmitLLVMAction;
206	  using MangledKernelNamesMap = cudaq::ASTBridgeAction::MangledKernelNamesMap;
207	
208	  CudaQAction(mlir::OwningOpRef<mlir::ModuleOp> &module,
209	              MangledKernelNamesMap &kernelNames)
210	      : mlirAction(module, kernelNames) {}
211	  virtual ~CudaQAction() = default;
212	
213	  std::unique_ptr<clang::ASTConsumer>
214	  CreateASTConsumer(clang::CompilerInstance &ci, StringRef inFile) override {
215	    auto llvmConsumer = this->Base::CreateASTConsumer(ci, inFile);
216	    auto mlirConsumer = mlirAction.CreateASTConsumer(ci, inFile);
217	    return std::make_unique<CudaQASTConsumer>(llvmConsumer, mlirConsumer);
218	  }
219	
220	private:
221	  cudaq::ASTBridgeAction mlirAction;
222	};
223	
224	/// This is the front-end action to convert the C++ code to LLVM IR to a file.
225	class InterceptCudaQAction : public clang::EmitLLVMAction {
226	public:
227	  using MangledKernelNamesMap = cudaq::ASTBridgeAction::MangledKernelNamesMap;
228	
229	  InterceptCudaQAction(mlir::OwningOpRef<mlir::ModuleOp> &,
230	                       MangledKernelNamesMap &)
231	      : clang::EmitLLVMAction{} {}
232	  virtual ~InterceptCudaQAction() = default;
233	
234	  void EndSourceFileAction() override {
235	    clang::EmitLLVMAction::EndSourceFileAction();
236	    // Dump the IR to stderr if the command-line option was given.
237	    if (dumpToStderr)
238	      takeModule().get()->print(errs(), nullptr, false, true);
239	  }
240	};
241	} // namespace
242	
243	template <typename ACTION>
244	bool runTool(mlir::OwningOpRef<mlir::ModuleOp> &module,
245	             CudaQAction::MangledKernelNamesMap &mangledKernelNameMap,
246	             StringRef cplusplusCode, std::vector<std::string> &clArgs,
247	             const std::string &inputFileName) {
248	  assert(cplusplusCode.size() > 0);
249	  assert(clArgs.size() > 0);
250	  if (!clang::tooling::runToolOnCodeWithArgs(
251	          std::make_unique<ACTION>(module, mangledKernelNameMap), cplusplusCode,
252	          clArgs, inputFileName, toolName)) {
253	    errs() << "error: could not translate ";
254	    if (inputFilename == "-")
255	      errs() << "input";
256	    else
257	      errs() << "file '" << inputFilename;
258	    errs() << '\n';
259	    return true; // failed
260	  }
261	  return false;
262	}
263	
264	/// @brief Retrieve the path of this executable, borrowed from
265	/// the Clang Driver
266	std::string getExecutablePath(const char *argv0, bool canonicalPrefixes) {
267	  if (!canonicalPrefixes) {
268	    SmallString<128> executablePath(argv0);
269	    if (!llvm::sys::fs::exists(executablePath))
270	      if (llvm::ErrorOr<std::string> p =
271	              llvm::sys::findProgramByName(executablePath))
272	        executablePath = *p;
273	    return std::string(executablePath.str());
274	  }
275	  void *p = (void *)(intptr_t)getExecutablePath;
276	  return llvm::sys::fs::getMainExecutable(argv0, p);
277	}
278	
279	//===----------------------------------------------------------------------===//
280	// Main entry point into the cudaq-quake tool.
281	//===----------------------------------------------------------------------===//
282	
283	int main(int argc, char **argv) {
284	  // Set the bug report message to indicate users should file issues on
285	  // nvidia/cuda-quantum
286	  llvm::setBugReportMsg(cudaq::bugReportMsg);
287	
288	  // We need the location of this cudaq-quake executable so that we can get the
289	  // install path
290	  std::string executablePath = getExecutablePath(argv[0], true);
291	  std::filesystem::path cudaqQuakePath{executablePath};
292	  auto installBinPath = cudaqQuakePath.parent_path();
293	  auto cudaqInstallPath = installBinPath.parent_path();
294	
295	  // Resolve LLVM install path: try the build-time LLVM_ROOT first, then
296	  // the installer's lib/llvm/ subtree inside the CUDAQ prefix.
297	  std::filesystem::path llvmInstallPath{LLVM_ROOT};
298	  if (!std::filesystem::exists(llvmInstallPath))
299	    llvmInstallPath = cudaqInstallPath / "lib" / "llvm";
300	
301	  std::filesystem::path resourceDirPath{resourceDir.getValue()};
302	#define STR_HELPER(x) #x
303	#define STR(x) STR_HELPER(x)
304	  if (!std::filesystem::exists(resourceDirPath))
305	    resourceDirPath =
306	        llvmInstallPath / "lib" / "clang" / STR(LLVM_VERSION_MAJOR);
307	  if (!std::filesystem::exists(resourceDirPath)) {
308	    llvm::errs() << "Could not find a valid clang resource-dir.\n";
309	    return 1;
310	  }
311	#undef STR
312	#undef STR_HELPER
313	
314	  // Process the command-line options, including reading in a file.
315	  [[maybe_unused]] llvm::InitLLVM unused(argc, argv);
316	  cl::ParseCommandLineOptions(argc, argv, toolName);
317	  ErrorOr<std::unique_ptr<MemoryBuffer>> fileOrError =
318	      MemoryBuffer::getFileOrSTDIN(inputFilename);
319	  if (auto ec = fileOrError.getError()) {
320	    errs() << "Could not open file: " << ec.message() << '\n';
321	    return ec.value();
322	  }
323	
324	  // Read the code into a memory buffer and setup MLIR.
325	  auto cplusplusCode = fileOrError.get()->getBuffer();
326	  mlir::DialectRegistry registry;
327	  cudaq::registerAllDialects(registry);
328	  mlir::MLIRContext context(registry);
329	  // TODO: Consider only loading the dialects we know we'll use.
330	  context.loadAllAvailableDialects();
331	  mlir::OpBuilder builder(&context);
332	  auto moduleOp = mlir::ModuleOp::create(builder.getUnknownLoc());
333	  mlir::OwningOpRef<mlir::ModuleOp> module(moduleOp);
334	  // Register trivial diagnostic handler so that notes, warnings, and
335	  // remark messages are not elided by default.
336	  context.getDiagEngine().registerHandler([](mlir::Diagnostic &diag) {
337	    const char *severity = "";
338	    switch (diag.getSeverity()) {
339	    case mlir::DiagnosticSeverity::Note:
340	      severity = "note";
341	      break;
342	    case mlir::DiagnosticSeverity::Warning:
343	      severity = "warning";
344	      break;
345	    case mlir::DiagnosticSeverity::Remark:
346	      severity = "remark";
347	      break;
348	    case mlir::DiagnosticSeverity::Error:
349	      severity = "error";
350	      break;
351	    }
352	    llvm::errs() << diag.getLocation() << ':' << severity << ": " << diag.str()
353	                 << '\n';
354	  });
355	
356	  // Process arguments.
357	  std::vector<std::string> clArgs = {"-std=" + stdCpp, "-resource-dir",
358	                                     resourceDirPath.string()};
359	  if (verboseClang)
360	    clArgs.push_back("-v");
361	
362	  if (debugMode)
363	    clArgs.push_back("-g");
364	
365	  // Update the include path.
366	  for (auto &path : systemIncludePath) {
367	    clArgs.push_back("-isystem");
368	    clArgs.push_back(path);
369	  }
370	
371	  // Configure C++ standard library headers. Try the CMake configure-time paths
372	  // first; if this binary has been relocated (e.g., via the installer), fall
373	  // back to the LLVM subtree resolved above (lib/llvm/include/...).
374	  std::filesystem::path resolvedLibcxxPath{std::string(CUDAQ_LIBCXX_PATH)};
375	  std::filesystem::path resolvedLibcxxTargetPath{
376	      std::string(CUDAQ_LIBCXX_TARGET_PATH)};
377	  const std::string sysrootPath = CUDAQ_SYSROOT_PATH;
378	  if (!resolvedLibcxxPath.empty() &&
379	      !std::filesystem::exists(resolvedLibcxxPath)) {
380	    resolvedLibcxxPath = llvmInstallPath / "include" / "c++" / "v1";
381	    resolvedLibcxxTargetPath =
382	        llvmInstallPath / "include" / LLVM_TARGET_TRIPLE / "c++" / "v1";
383	  }
384	  if (!resolvedLibcxxPath.empty() &&
385	      std::filesystem::exists(resolvedLibcxxPath)) {
386	    clArgs.push_back("-nostdinc++");
387	    if (std::filesystem::exists(resolvedLibcxxTargetPath)) {
388	      clArgs.push_back("-isystem");
389	      clArgs.push_back(resolvedLibcxxTargetPath.string());
390	    }
391	    clArgs.push_back("-isystem");
392	    clArgs.push_back(resolvedLibcxxPath.string());
393	    if (!sysrootPath.empty()) {
394	      clArgs.push_back("-isysroot");
395	      clArgs.push_back(sysrootPath);
396	    }
397	  } else if (!sysrootPath.empty()) {
398	    clArgs.push_back("-isysroot");
399	    clArgs.push_back(sysrootPath);
400	  }
401	
402	  // If the cudaq.h does not exist in the installation directory, fallback onto
403	  // the source install.
404	  std::filesystem::path cudaqIncludeDir = cudaqInstallPath / "include";
405	  auto cudaqHeader = cudaqIncludeDir / "cudaq.h";
406	  bool useFallbackIncludes = false;
407	  if (!std::filesystem::exists(cudaqHeader)) {
408	    // need to fall back to the build environment.
409	    cudaqIncludeDir = std::string(FALLBACK_CUDAQ_INCLUDE_DIR);
410	    useFallbackIncludes = true;
411	  }
412	  // One final check here, do we have this header, if not we cannot proceed.
413	  if (!std::filesystem::exists(cudaqIncludeDir / "cudaq.h")) {
414	    llvm::errs() << "Invalid CUDA-Q install configuration, cannot find "
415	                    "CUDA-Q include directory.\n";
416	    return 1;
417	  }
418	
419	  // Attach the relative path of the file, if any. The directory the file
420	  // resides in has highest priority.
421	  std::string relativePath = sys::path::parent_path(inputFilename).str();
422	  if (!relativePath.empty())
423	    clArgs.push_back("-I" + relativePath);
424	
425	  for (auto &path : includePath)
426	    clArgs.push_back("-I" + path);
427	
428	  // Add the default path to the cudaq headers.
429	  clArgs.push_back("-I" + cudaqIncludeDir.string());
430	
431	  // Add the new runtime include path if needed
432	  if (useFallbackIncludes) {
433	    clArgs.push_back("-I" + std::string(FALLBACK_REFACTORED_CUDAQ_INCLUDE_DIR));
434	    clArgs.push_back("-I" +
435	                     std::string(FALLBACK_CUDAQ_INTERNAL_COMPILER_INCLUDE_DIR));
436	    clArgs.push_back("-I" + std::string(FALLBACK_CUDAQ_SUPPORT_DIR));
437	    clArgs.push_back("-I" + std::string(FALLBACK_JSON_INCLUDE_DIR));
438	  }
439	  // Add preprocessor macro definitions, if any.
440	  for (auto &def : macroDefines)
441	    clArgs.push_back("-D" + def);
442	
443	  // Pass verify mode if requested.
444	  if (verifyMode) {
445	    clArgs.push_back("-Xclang");
446	    clArgs.push_back("-verify");
447	  }
448	  // Pass -ast-dump if requested.
449	  if (astDump) {
450	    clArgs.push_back("-Xclang");
451	    clArgs.push_back("-ast-dump");
452	  }
453	
454	  for (auto &xtra : extraClangArgs)
455	    clArgs.push_back(xtra);
456	
457	  // Allow a user to specify extra args for clang via an environment variable.
458	  if (auto extraArgs = std::getenv("CUDAQ_CLANG_EXTRA_ARGS")) {
459	    std::stringstream ss;
460	    ss << extraArgs;
461	    std::string part;
462	    std::vector<std::string> localArgs;
463	    while (std::getline(ss, part, ' '))
464	      clArgs.push_back(part);
465	  }
466	
467	  // Set the mangled kernel names map.
468	  CudaQAction::MangledKernelNamesMap mangledKernelNameMap;
469	
470	  std::string inputFile = isStdinInput(inputFilename)
471	                              ? std::string("input.cc")
472	                              : sys::path::filename(inputFilename).str();
473	  if (auto rc = emitLLVM
474	                    ? runTool<CudaQAction>(module, mangledKernelNameMap,
475	                                           cplusplusCode, clArgs, inputFile)
476	                    : (llvmOnly ? runTool<InterceptCudaQAction>(
477	                                      module, mangledKernelNameMap,
478	                                      cplusplusCode, clArgs, inputFile)
479	                                : runTool<cudaq::ASTBridgeAction>(
480	                                      module, mangledKernelNameMap,
481	                                      cplusplusCode, clArgs, inputFile)))
482	    return rc;
483	
484	  // Success! Dump the IR and exit.
485	  std::error_code ec;
486	  ToolOutputFile out(outputFilename, ec, sys::fs::OF_None);
487	  if (ec) {
488	    errs() << "Failed to open output file '" << outputFilename << "'\n";
489	    return ec.value();
490	  }
491	  if (!moduleOp.getBody()->empty()) {
492	    if (!mangledKernelNameMap.empty()) {
493	      SmallVector<mlir::NamedAttribute> names;
494	      for (auto [key, value] : mangledKernelNameMap)
495	        names.emplace_back(mlir::StringAttr::get(&context, key),
496	                           mlir::StringAttr::get(&context, value));
497	      auto mapAttr = mlir::DictionaryAttr::get(&context, names);
498	      moduleOp->setAttr(cudaq::runtime::mangledNameMap, mapAttr);
499	    }
500	
501	    // Running the verifier to make it easier to track down errors.
502	    // The canonicalizer and symbol DCE passes cleanup unused artifacts
503	    // generated by the bridge.
504	    mlir::PassManager pm(&context);
505	    pm.addPass(std::make_unique<cudaq::VerifierPass>());
506	    if (!noSimplify) {
507	      pm.addPass(mlir::createCanonicalizerPass());
508	      pm.addPass(mlir::createSymbolDCEPass());
509	    }
510	    if (failed(pm.run(moduleOp))) {
511	      moduleOp->dump();
512	      llvm::errs() << "Passes failed!\n";
513	    } else {
514	      mlir::OpPrintingFlags opf;
515	      opf.enableDebugInfo(/*enable=*/true,
516	                          /*pretty=*/false);
517	      moduleOp.print(out.os(), opf);
518	      out.os() << '\n';
519	      out.keep();
520	    }
521	  }
522	
523	  return 0;
524	}
